input.command:
Write-Host "---WIFI PROFILE---"; Get-NetConnectionProfile | Format-Table Name, InterfaceAlias, NetworkCategory, IPv4Connectivity -AutoSize; Write-Host "---ADD FW RULES---"; $rules = @(
  @{ Name = "Elay Customer API HTTPS 8181"; Port = 8181 },
  @{ Name = "Elay Customer API HTTP 8180"; Port = 8180 }
); foreach ($r in $rules) {
  $existing = Get-NetFirewallRule -DisplayName $r.Name -ErrorAction SilentlyContinue
  if ($existing) {
    Write-Host "EXISTS: $($r.Name) - enabling"
    Set-NetFirewallRule -DisplayName $r.Name -Enabled True -Action Allow -Profile Any
  } else {
    New-NetFirewallRule -DisplayName $r.Name -Direction Inbound -Action Allow -Protocol TCP -LocalPort $r.Port -Profile Any -Enabled True | Out-Null
    Write-Host "CREATED: $($r.Name) TCP $($r.Port)"
  }
}; Write-Host "---VERIFY RULES---"; Get-NetFirewallRule -DisplayName "Elay Customer API*" | Select-Object DisplayName, Enabled, Direction, Action, Profile | Format-Table -AutoSize; Get-NetFirewallPortFilter | Where-Object { $_.LocalPort -eq 8181 -or $_.LocalPort -eq 8180 } | ForEach-Object { $rule = $_ | Get-NetFirewallRule; [PSCustomObject]@{ DisplayName=$rule.DisplayName; Port=$_.LocalPort; Enabled=$rule.Enabled; Action=$rule.Action } } | Format-Table -AutoSize

$token = (Get-Content "d:\Elay_Backend-master\Customer\Api\appsettings.json" -Raw | ConvertFrom-Json).HttpClient.Token; $headers = @{ Authorization = "Bearer $token" }; $urls = @(
  "http://admin.api.elaiapp.ir/reports/1_Report_12393_0.mrt",
  "http://admin.api.elaiapp.ir/reports/2_%DA%86%DA%A9%20%D9%84%DB%8C%D8%B3%D8%AA%20%D8%A7%DB%8C%D9%85%D9%86%DB%8C%20%D8%A8%D8%A7%D8%B2%D8%AF%DB%8C%D8%AF%20%D9%84%D9%88%D8%AF%D8%B1.mrt"
); foreach ($u in $urls) {
  Write-Host "=== $u ==="
  try { $r = Invoke-WebRequest -Uri $u -Headers $headers -Method GET -TimeoutSec 20; "GET $($r.StatusCode) len=$($r.RawContentLength)" } catch { "GET FAIL: $([int]$_.Exception.Response.StatusCode) $($_.Exception.Message)" }
}
